server/tests/test_histogram.py :: test_rgb_histograms_have_three_channels
def test_rgb_histograms_have_three_channels() -> None:
    raster = gradient_raster(8, 6)
    histograms = rgb_histograms(raster, buckets=8)
    assert set(histograms) == {"red", "green", "blue"}
    assert all(sum(values) == 48 for values in histograms.values())
